exec('from fastapi.testclient import TestClient\nfrom app.main import app\nclient=TestClient(app)\ndef test_health():\n    r=client.get("/api/health"); assert r.status_code==200; assert r.json()["status"]=="ok"\ndef test_session_and_analyze_flow():\n    s=client.post("/api/session",json={"note_id":"demo-note-001"}); assert s.status_code==200; token=s.json()["token"]\n    manual=chr(10).join(["所在地: 東京都サンプル区1-2-3","土地面積: 180.25㎡","用途地域: 第一種住居地域","建ぺい率: 60%","容積率: 300%","前面道路幅員: 4.0m","平均住戸面積: 45㎡"])\n    r=client.post("/api/analyze",data={"token":token,"manual_text":manual},files={"file":("plan.txt",b"dummy","text/plain")}); assert r.status_code==200\n    p=r.json(); assert p["result"]["inputs"]["land_area_m2"]==180.25; assert p["result"]["calculation"]["applied_far_percent"]==160.0; assert set(p["exports"].keys())=={"csv","xlsx","txt"}\ndef test_invalid_note_id_rejected():\n    r=client.post("/api/session",json={"note_id":"not-allowed"}); assert r.status_code==403\n')